import{_ as e,o as s,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Android App","description":"","frontmatter":{"summary":"Android app (node): connection runbook + Canvas/Chat/Camera","read_when":["Pairing or reconnecting the Android node","Debugging Android gateway discovery or auth","Verifying chat history parity across clients"],"title":"Android App"},"headers":[],"relativePath":"platforms/android.md","filePath":"platforms/android.md","lastUpdated":1771906665000}'),t={name:"platforms/android.md"};function o(d,a,r,l,h,p){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="android-app-node" tabindex="-1"><a class="header-anchor" href="#android-app-node">#</a> Android App (Node)</h1><h2 id="support-snapshot" tabindex="-1"><a class="header-anchor" href="#support-snapshot">#</a> Support snapshot</h2><ul><li>Role: companion node app (Android does not host the Gateway).</li><li>Gateway required: yes (run it on macOS, Linux, or Windows via WSL2).</li><li>Install: <a href="/docs/start/getting-started">Getting Started</a> + <a href="/docs/gateway/pairing">Pairing</a>.</li><li>Gateway: <a href="/docs/gateway/index">Runbook</a> + <a href="/docs/gateway/configuration">Configuration</a>. <ul><li>Protocols: <a href="/docs/gateway/protocol">Gateway protocol</a> (nodes + control plane).</li></ul></li></ul><h2 id="system-control" tabindex="-1"><a class="header-anchor" href="#system-control">#</a> System control</h2><p>System control (launchd/systemd) lives on the Gateway host. See <a href="/docs/gateway/index">Gateway</a>.</p><h2 id="connection-runbook" tabindex="-1"><a class="header-anchor" href="#connection-runbook">#</a> Connection Runbook</h2><p>Android node app ⇄ (mDNS/NSD + WebSocket) ⇄ <strong>Gateway</strong></p><p>Android connects directly to the Gateway WebSocket (default <code>ws://&lt;host&gt;:18789</code>) and uses Gateway-owned pairing.</p><h3 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites">#</a> Prerequisites</h3><ul><li>You can run the Gateway on the “master” machine.</li><li>Android device/emulator can reach the gateway WebSocket: <ul><li>Same LAN with mDNS/NSD, <strong>or</strong></li><li>Same Tailscale tailnet using Wide-Area Bonjour / unicast DNS-SD (see below), <strong>or</strong></li><li>Manual gateway host/port (fallback)</li></ul></li><li>You can run the CLI (<code>opensoul</code>) on the gateway machine (or via SSH).</li></ul><h3 id="_1-start-the-gateway" tabindex="-1"><a class="header-anchor" href="#_1-start-the-gateway">#</a> 1) Start the Gateway</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Confirm in logs you see something like:</p><ul><li><code>listening on ws://0.0.0.0:18789</code></li></ul><p>For tailnet-only setups (recommended for Vienna ⇄ London), bind the gateway to the tailnet IP:</p><ul><li>Set <code>gateway.bind: &quot;tailnet&quot;</code> in <code>~/.opensoul/opensoul.json</code> on the gateway host.</li><li>Restart the Gateway / macOS menubar app.</li></ul><h3 id="_2-verify-discovery-optional" tabindex="-1"><a class="header-anchor" href="#_2-verify-discovery-optional">#</a> 2) Verify discovery (optional)</h3><p>From the gateway machine:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _opensoul-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>More debugging notes: <a href="/docs/gateway/bonjour">Bonjour</a>.</p><h4 id="tailnet-vienna-⇄-london-discovery-via-unicast-dns-sd" tabindex="-1"><a class="header-anchor" href="#tailnet-vienna-⇄-london-discovery-via-unicast-dns-sd">#</a> Tailnet (Vienna ⇄ London) discovery via unicast DNS-SD</h4><p>Android NSD/mDNS discovery won’t cross networks. If your Android node and the gateway are on different networks but connected via Tailscale, use Wide-Area Bonjour / unicast DNS-SD instead:</p><ol><li>Set up a DNS-SD zone (example <code>opensoul.internal.</code>) on the gateway host and publish <code>_opensoul-gw._tcp</code> records.</li><li>Configure Tailscale split DNS for your chosen domain pointing at that DNS server.</li></ol><p>Details and example CoreDNS config: <a href="/docs/gateway/bonjour">Bonjour</a>.</p><h3 id="_3-connect-from-android" tabindex="-1"><a class="header-anchor" href="#_3-connect-from-android">#</a> 3) Connect from Android</h3><p>In the Android app:</p><ul><li>The app keeps its gateway connection alive via a <strong>foreground service</strong> (persistent notification).</li><li>Open <strong>Settings</strong>.</li><li>Under <strong>Discovered Gateways</strong>, select your gateway and hit <strong>Connect</strong>.</li><li>If mDNS is blocked, use <strong>Advanced → Manual Gateway</strong> (host + port) and <strong>Connect (Manual)</strong>.</li></ul><p>After the first successful pairing, Android auto-reconnects on launch:</p><ul><li>Manual endpoint (if enabled), otherwise</li><li>The last discovered gateway (best-effort).</li></ul><h3 id="_4-approve-pairing-cli" tabindex="-1"><a class="header-anchor" href="#_4-approve-pairing-cli">#</a> 4) Approve pairing (CLI)</h3><p>On the gateway machine:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pending</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">requestI</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Pairing details: <a href="/docs/gateway/pairing">Gateway pairing</a>.</p><h3 id="_5-verify-the-node-is-connected" tabindex="-1"><a class="header-anchor" href="#_5-verify-the-node-is-connected">#</a> 5) Verify the node is connected</h3><ul><li><p>Via nodes status:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>Via Gateway:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> call</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node.list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;{}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><h3 id="_6-chat-history" tabindex="-1"><a class="header-anchor" href="#_6-chat-history">#</a> 6) Chat + history</h3><p>The Android node’s Chat sheet uses the gateway’s <strong>primary session key</strong> (<code>main</code>), so history and replies are shared with WebChat and other clients:</p><ul><li>History: <code>chat.history</code></li><li>Send: <code>chat.send</code></li><li>Push updates (best-effort): <code>chat.subscribe</code> → <code>event:&quot;chat&quot;</code></li></ul><h3 id="_7-canvas-camera" tabindex="-1"><a class="header-anchor" href="#_7-canvas-camera">#</a> 7) Canvas + camera</h3><h4 id="gateway-canvas-host-recommended-for-web-content" tabindex="-1"><a class="header-anchor" href="#gateway-canvas-host-recommended-for-web-content">#</a> Gateway Canvas Host (recommended for web content)</h4><p>If you want the node to show real HTML/CSS/JS that the agent can edit on disk, point the node at the Gateway canvas host.</p><p>Note: nodes use the standalone canvas host on <code>canvasHost.port</code> (default <code>18793</code>).</p><ol><li><p>Create <code>~/.opensoul/workspace/canvas/index.html</code> on the gateway host.</p></li><li><p>Navigate the node to it (LAN):</p></li></ol><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> invoke</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;Android Node&gt;&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --command</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> canvas.navigate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --params</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;url&quot;:&quot;http://&lt;gateway-hostname&gt;.local:18793/__opensoul__/canvas/&quot;}&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Tailnet (optional): if both devices are on Tailscale, use a MagicDNS name or tailnet IP instead of <code>.local</code>, e.g. <code>http://&lt;gateway-magicdns&gt;:18793/__opensoul__/canvas/</code>.</p><p>This server injects a live-reload client into HTML and reloads on file changes. The A2UI host lives at <code>http://&lt;gateway-host&gt;:18793/__opensoul__/a2ui/</code>.</p><p>Canvas commands (foreground only):</p><ul><li><code>canvas.eval</code>, <code>canvas.snapshot</code>, <code>canvas.navigate</code> (use <code>{&quot;url&quot;:&quot;&quot;}</code> or <code>{&quot;url&quot;:&quot;/&quot;}</code> to return to the default scaffold). <code>canvas.snapshot</code> returns <code>{ format, base64 }</code> (default <code>format=&quot;jpeg&quot;</code>).</li><li>A2UI: <code>canvas.a2ui.push</code>, <code>canvas.a2ui.reset</code> (<code>canvas.a2ui.pushJSONL</code> legacy alias)</li></ul><p>Camera commands (foreground only; permission-gated):</p><ul><li><code>camera.snap</code> (jpg)</li><li><code>camera.clip</code> (mp4)</li></ul><p>See <a href="/docs/nodes/camera">Camera node</a> for parameters and CLI helpers.</p>`,51)])])}const g=e(t,[["render",o]]);export{u as __pageData,g as default};
